    @hatchet.step()
    def step1(self, context: Context):
        print("--- Executing Step 1 ---")
        log_path = "/home/user/project/output.log"
        with open(log_path, "a") as f:
            f.write("step1\n")
        return {"status": "step1_done"}

    @hatchet.step(parents=["step1"])
    def step2(self, context: Context):
        print("--- Executing Step 2 ---")
        flag_path = "/home/user/project/crashed.flag"
        log_path = "/home/user/project/output.log"

        if not os.path.exists(flag_path):
            print("Crash flag not found. Creating flag and crashing...")
            with open(flag_path, "w") as f:
                f.write("crashed")
            # Forcefully crash the worker process
            os._exit(1)

        print("Crash flag found. Resuming and completing Step 2.")
        with open(log_path, "a") as f:
            f.write("step2\n")
        return {"status": "step2_done"}

if __name__ == "__main__":
    worker = hatchet.worker("recovery-worker")
    worker.register_workflow(FailureRecoveryWorkflow())
    worker.start()

